n = int(input())
A = list(map(int, input().split()))

# Create a 2D table to store the maximum difference for each subarray
dp = [[0]*n for _ in range(n)]

# Initialize the diagonal elements to 0
for i in range(n):
    dp[i][i] = 0

# Fill the table in a bottom-up manner
for length in range(1, n):
    for i in range(n - length):
        j = i + length
        if A[i] <= A[j]:
            dp[i][j] = max(dp[i][j-1], j - i)
        else:
            dp[i][j] = dp[i][j-1]

# The maximum difference is stored in the top-right corner of the table
result = max(max(row) for row in dp)

